// Only run on the first Monday of the month
const today = new Date();
if (today.getDate() > 7) {
  return []; // Not first week of month
}
return [{ json: { run: true, report_month: today.toISOString().substring(0, 7) + '-01' } }];

const userId = $('Get Users With Data').item.json.user_id;
const reportMonth = $('Check First Monday').item.json.report_month;
const indicators = $('Get Month Indicators').all().map(i => i.json);
const patterns = $('Get Patterns').all().map(i => i.json);

// Count by type
const winCount = indicators.filter(i => i.indicator_type === 'win').length;
const lossCount = indicators.filter(i => i.indicator_type === 'loss').length;
const switchCount = indicators.filter(i => i.indicator_type === 'switch').length;

// Companies analyzed
const companies = [...new Set(indicators.map(i => i.company_name))];

// Build report content
const winPatterns = patterns.filter(p => p.pattern_type === 'win').slice(0, 5);
const lossPatterns = patterns.filter(p => p.pattern_type === 'loss').slice(0, 5);
const switchPatterns = patterns.filter(p => p.pattern_type === 'switch').slice(0, 5);

const monthName = new Date(reportMonth).toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
const title = `Win/Loss Report — ${monthName}`;

const md = `# ${title}\n\n**Period:** ${monthName}\n**Total Indicators:** ${indicators.length} (${winCount} win, ${lossCount} loss, ${switchCount} switch)\n**Companies Analyzed:** ${companies.join(', ')}\n\n---\n\n## Top Win Patterns\n${winPatterns.map(p => `- **${p.company_name}**: ${p.description} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n## Top Loss Patterns\n${lossPatterns.map(p => `- **${p.company_name}**: ${p.description} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n## Switch Patterns\n${switchPatterns.map(p => `- **${p.company_name}**: ${p.description} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n---\n*Generated by Signal Plane Win/Loss Intelligence*`;

const contentJson = {
  win_count: winCount,
  loss_count: lossCount,
  switch_count: switchCount,
  total_indicators: indicators.length,
  companies: companies,
  top_win_patterns: winPatterns,
  top_loss_patterns: lossPatterns,
  top_switch_patterns: switchPatterns
};

return [{
  json: {
    user_id: userId,
    report_month: reportMonth,
    title: title,
    content_json: JSON.stringify(contentJson),
    content_md: md,
    indicator_count: indicators.length,
    pattern_count: patterns.length,
    companies_analyzed: companies
  }
}];
